mapper.select:
SELECT d.device_id AS deviceId, d.device_code AS deviceCode, d.device_name AS deviceName, d.device_type AS deviceType, CASE d.device_type WHEN 1 THEN '静态心电设备' WHEN 2 THEN '动态心电设备' WHEN 3 THEN '居家监护设备' WHEN 4 THEN '床边监护仪' ELSE '未知' END AS deviceTypeText, d.device_model AS deviceModel, d.manufacturer AS manufacturer, d.supplier AS supplier, d.install_date AS installDate, d.bind_dept_id AS wardId, d.bind_dept_name AS wardName, d.device_status AS deviceStatus, CASE d.device_status WHEN 1 THEN '正常' WHEN 2 THEN '维修' WHEN 3 THEN '停用' WHEN 4 THEN '离线' ELSE '未知' END AS deviceStatusText, d.last_maintain_time AS lastMaintainTime, d.next_maintain_time AS nextMaintainTime FROM ecg_device d WHERE d.is_deleted = 0
AND ( d.device_name LIKE CONCAT('%', #{req.deviceName}, '%') OR d.device_code LIKE CONCAT('%', #{req.deviceName}, '%') )
AND d.device_type = #{deviceTypeCode}
AND ( d.bind_dept_name = #{req.ward} OR CAST(d.bind_dept_id AS CHAR) = #{req.ward} )
AND d.install_date >= #{purchaseStart}
AND d.install_date <= #{purchaseEnd}
ORDER BY d.update_time DESC, d.device_id DESC

SELECT COUNT(1)
FROM ecg_device d
WHERE d.device_code = #{deviceCode}

    AND d.device_id != #{excludeDeviceId}
